from fastapi import FastAPI
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
import stripe
import os
from dotenv import load_dotenv

load_dotenv()

app = FastAPI(title='Payment API')

stripe.api_key = os.environ.get('STRIPE_SECRET_KEY', '')
STRIPE_WEBHOOK_SECRET = os.environ.get('STRIPE_WEBHOOK_SECRET', '')
STRIPE_PUBLISHABLE_KEY = os.environ.get('STRIPE_PUBLISHABLE_KEY', '')

class PaymentRequest(BaseModel):
    amount_cents: int
    description: str

@app.post('/create-payment-intent')
def create_payment_intent(req: PaymentRequest):
    intent = stripe.PaymentIntent.create(
        amount=req.amount_cents,
        currency='usd',
        description=req.description,
        automatic_payment_methods={'enabled': True}
    )
    return {'client_secret': intent.client_secret}

@app.get('/checkout', response_class=HTMLResponse)
def checkout_page():
    return f"""
    <!DOCTYPE html><html><head>
    <script src="https://js.stripe.com/v3/"></script>
    </head><body>
    <h1>Checkout</h1>
    <div id="payment-element"></div>
    <button id="pay">Pay $9.99</button>
    <div id="message"></div>
    <script>
      const stripe = Stripe('{STRIPE_PUBLISHABLE_KEY}');
      fetch('/create-payment-intent', {{
        method: 'POST',
        headers: {{'Content-Type': 'application/json'}},
        body: JSON.stringify({{amount_cents: 999, description: 'Coffee'}})
      }}).then(r => r.json()).then(data => {{
        const elements = stripe.elements({{clientSecret: data.client_secret}});
        elements.create('payment').mount('#payment-element');
        document.getElementById('pay').addEventListener('click', async () => {{
          const result = await stripe.confirmPayment({{
            elements,
            confirmParams: {{return_url: 'http://localhost:8000/success'}}
          }});
          if (result.error) document.getElementById('message').textContent = result.error.message;
        }});
      }});
    </script></body></html>
    """

@app.get('/success')
def success():
    return {'message': 'Payment successful!'}
